151 static bool canWidenLoad(LoadInst *Load, const TargetTransformInfo &TTI) {
152   // Do not widen load if atomic/volatile or under asan/hwasan/memtag/tsan.
153   // The widened load may load data from dirty regions or create data races
154   // non-existent in the source.
155   if (!Load || !Load->isSimple() || !Load->hasOneUse() ||
156       Load->getFunction()->hasFnAttribute(Attribute::SanitizeMemTag) ||
157       mustSuppressSpeculation(*Load))
158     return false;
159 
160   // We are potentially transforming byte-sized (8-bit) memory accesses, so make
161   // sure we have all of our type-based constraints in place for this target.
162   Type *ScalarTy = Load->getType()->getScalarType();
163   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
164   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
165   if (!ScalarSize || !MinVectorSize || MinVectorSize % ScalarSize != 0 ||
166       ScalarSize % 8 != 0)
167     return false;
168 
169   return true;
170 }
