2529   InstructionCost ShrinkCost = 0;
2530 
2531   // Calculate total cost and check that we can propagate through all ZExt users
2532   for (User *U : ZExtOperand->users()) {
2533     auto *UI = cast<Instruction>(U);
2534     if (UI == &I) {
2535       CurrentCost +=
2536           TTI.getArithmeticInstrCost(UI->getOpcode(), BigTy, CostKind);
